import{_ as e,o as t,c as o,O as a}from"./chunks/framework.bdcb0ee1.js";const m=JSON.parse('{"title":"Reactions","description":"","frontmatter":{},"headers":[],"relativePath":"administration/config/reactions.md","filePath":"administration/config/reactions.md","lastUpdated":1773166533000}'),s={name:"administration/config/reactions.md"},n=a('<h1 id="reactions" tabindex="-1">Reactions <a class="header-anchor" href="#reactions" aria-label="Permalink to &quot;Reactions&quot;">​</a></h1><p>ForumSpark allows you to define custom reactions that users can give to posts. These can be used for quick feedback (like, agree, thanks, etc.) and can optionally contribute to a user’s overall reaction score.</p><p>You can access the <strong>Reactions</strong> panel from the <strong>Board Config</strong> section in the Admin Control Panel.</p><h2 id="adding-a-reaction" tabindex="-1">Adding a Reaction <a class="header-anchor" href="#adding-a-reaction" aria-label="Permalink to &quot;Adding a Reaction&quot;">​</a></h2><p>To define a new reaction, fill out the following fields:</p><ul><li><strong>Reaction Name</strong>: The label that will be shown in tooltips and for accessibility purposes.</li><li><strong>Emoji</strong>: An optional emoji to use as the visual for the reaction. If this is set, it takes priority over the custom image.</li><li><strong>Custom Image</strong>: An optional custom image URL. Only one of <strong>Emoji</strong> or <strong>Custom Image</strong> is required. If you use an image, upload it via the <strong>File Manager</strong> and paste the URL here.</li><li><strong>Reaction Score</strong>: A number used to increase or decrease the recipient&#39;s total reaction score when this reaction is received. Each user’s reaction only contributes once per post.</li><li><strong>Display Order</strong>: Controls where this reaction appears in reaction lists. Lower numbers appear first.</li></ul><img width="1949" height="901" alt="image" src="https://github.com/user-attachments/assets/f7c21b5a-676a-4419-a9c1-46fa79c91323"><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Users can give <strong>multiple different reactions</strong> to the same post, but not the <strong>same reaction more than once</strong>.</li><li>Reaction scores only apply <strong>once per user per reaction per post</strong>.</li><li>Reactions appear beneath posts and are visible to all users.</li><li>You can combine emoji-based and image-based reactions across your board, but each reaction must use only one type.</li></ul>',9),i=[n];function r(c,l,d,h,u,p){return t(),o("div",null,i)}const f=e(s,[["render",r]]);export{m as __pageData,f as default};
